2	
3	import { Logger } from '@nestjs/common';
4	import { FastifyRequest, FastifyReply, FastifyPluginCallback } from 'fastify';
5	import { HttpHeader } from 'fastify/types/utils';
6	import fp from 'fastify-plugin';
7	
8	import { isDevEnv } from '@utils/common.util';
9	
10	const FIELDS_WITH_SENSITIVE_DATA = [
11		'req.body.password',
12		'req.body.email',
13		'req.body.tenant',
14		'req.body.recipient',
15		'req.headers.cookie',
16		'req.headers.authorization',
17		'req.headers.proxyAuthorization',
18		'res.headers.cookie',
19		'res.headers["set-cookie"]',
20		'res.headers.authorization',
21		'res.headers.proxyAuthorization',
22	];
23	
24	export const logHttpRequest = (
25		req: FastifyRequest,
26		res: FastifyReply,
27		error?: Error,
28	): void => {
29		const logger = new Logger('HTTP Request');
30		const body = req.body ?? {};
31		const requestHeaders = req.headers;
32		const method = req.method;
33		const url = req.url;
34		const originalUrl = req.originalUrl;
35		const responseHeaders = res.getHeaders();
36		const statusCode = res.statusCode;
37		const ips = req.ips;
38		const ip = req.ip;
39	
40		const validateHeaders = (
41			headers:
42				| IncomingHttpHeaders
43				| Record<HttpHeader, string | number | string[] | undefined>,
44		): Record<string, string> =>
45			Object.entries(headers).reduce<Record<string, string>>((acc, [key, value]) => {
46				if (FIELDS_WITH_SENSITIVE_DATA.includes(`req.headers.${key}`)) {
47					acc[key] = isDevEnv() ? JSON.stringify(value) : '*****';
48				} else {
49					acc[key] = JSON.stringify(value);
50				}
51				return acc;
52			}, {});
53	
54		const validatedBody = Object.entries(body).reduce<Record<string, string>>(
55			(acc, [key, value]) => {
56				if (FIELDS_WITH_SENSITIVE_DATA.includes(`req.body.${key}`)) {
57					acc[key] = isDevEnv() ? JSON.stringify(value) : '*****';
58				} else {
59					acc[key] = JSON.stringify(value);
60				}
61				return acc;
62			},
63			{},
64		);
65	
66		const isErrorStatus = statusCode >= 400;
67		const logMethod = isErrorStatus || error ? 'error' : 'log';
68	
69		const logData: Record<string, unknown> = {
70			req: {
71				method,
72				url,
73				originalUrl,
74				ips,
75				ip,
76				headers: validateHeaders(requestHeaders),
77				body: validatedBody,
78			},
79			res: { statusCode, headers: validateHeaders(responseHeaders) },
80		};
81	
82		if (error) {
83			logData['error'] = {
84				message: error.message,
85				name: error.name,
86				stack: error.stack,
87			};
88		}
89	
90		logger[logMethod](logData);
91	};
92	
93	const httpLoggerPlugin: FastifyPluginCallback = (fastify, _options, done) => {
94		fastify.addHook('onResponse', (request, reply, done) => {
95			if (reply.statusCode === 404) {
96				const notFoundError = new Error(
97					`Route not found: ${request.method} ${request.url}`,
98				);
99				notFoundError.name = 'NotFoundError';
100				logHttpRequest(request, reply, notFoundError);
101			} else {
102				logHttpRequest(request, reply);
103			}
104			done();
105		});
106	
107		fastify.addHook('onError', (request, reply, error, done) => {
108			logHttpRequest(request, reply, error);
109			done();
110		});
111	
112		done();
113	};
114	
115	export const fastifyHttpLogger = fp(httpLoggerPlugin, {
116		name: 'fastify-http-logger',
117	});
